import java.util.*;
import java.util.concurrent.*;
import org.springframework.stereotype.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;

// BAD: ThreadLocal never cleaned up
class LeakyFilter {
    private static final ThreadLocal<Map<String, Object>> requestContext =
        new ThreadLocal<>();

    public void doFilter(String requestId) {
        Map<String, Object> ctx = new HashMap<>();
        ctx.put("requestId", requestId);
        ctx.put("largeData", new byte[1024 * 1024]);  // 1MB per request!
        requestContext.set(ctx);
        // LEAK: never removes ctx from ThreadLocal
        // Thread pool reuse: each thread accumulates Maps
    }
}

// GOOD: Always remove in finally
@Service
public class SafeRequestContextFilter {
    private static final ThreadLocal<Map<String, String>> requestContext =
        ThreadLocal.withInitial(HashMap::new);

    public void processRequest(String requestId, Runnable work) {
        requestContext.get().put("requestId", requestId);
        try {
            work.run();
        } finally {
            requestContext.remove();  // ALWAYS remove — prevents leak
        }
    }

    public String getRequestId() {
        return requestContext.get().getOrDefault("requestId", "unknown");
    }
}

@SpringBootTest
class ThreadLocalLeakTest {
    @Autowired SafeRequestContextFilter filter;

    @Test
    void noLeakAfterRequests() {
        for (int i = 0; i < 100; i++) {
            int id = i;
            filter.processRequest("REQ-" + id, () ->
                assertEquals("REQ-" + id, filter.getRequestId())
            );
            // After processRequest: ThreadLocal cleared (remove() called in finally)
        }
        // Memory stays constant (no leaked Maps)
        // This test implicitly validates the pattern works without growing
    }
}

// HEAP DUMP ANALYSIS WORKFLOW

// 1. Enable automatic heap dump on OOM (in Dockerfile/JAVA_TOOL_OPTIONS):
// -XX:+HeapDumpOnOutOfMemoryError
// -XX:HeapDumpPath=/tmp/payment-service-heapdump.hprof
// Docker: mount /tmp as volume to persist the dump after pod crash

// 2. Get heap dump from running pod (before OOM):
// Get JVM PID: kubectl exec <pod> -- jps -v  → find the java process PID
// Get heap dump:
// kubectl exec <pod> -- jmap -dump:format=b,file=/tmp/heap.hprof <PID>
// Copy to local: kubectl cp <pod>:/tmp/heap.hprof ./heap.hprof
// Alternative: jcmd <PID> VM.flags → confirm settings

// 3. Analyze with Eclipse Memory Analyzer (MAT) or VisualVM:
// Open heap.hprof
// 'Leak Suspects': MAT auto-identifies likely leaks
// 'Dominator Tree': shows largest retained heap objects
// 'OQL': query objects like SQL

// 4. COMMON CULPRITS:
public class HeapLeakPatterns {
    // CULPRIT 1: Static collection growing unboundedly
    private static final Map<String, CachedData> CACHE = new HashMap<>();  // NEVER cleared!
    // Fix: use Caffeine cache with maxSize + expiry:
    // private static final Cache<String, CachedData> CACHE =
    //   Caffeine.newBuilder().maximumSize(1000).expireAfterWrite(10, MINUTES).build();

    // CULPRIT 2: ThreadLocal not cleared
    private static final ThreadLocal<List<String>> local = new ThreadLocal<>();
    // Fix: always call local.remove() in finally block

    // CULPRIT 3: Event listeners not deregistered
    // Fix: @EventListener with @Transactional or @ApplicationListener
    //       that removes itself: applicationContext.removeApplicationListener(this);

    // CULPRIT 4: InputStream not closed
    // Fix: try-with-resources: try (InputStream is = ...) { ... }

    public static void main(String[] a) {
        System.out.println("Heap dump: jmap -dump → copy → analyze with MAT");
    }
}

