import io.micrometer.core.instrument.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.util.*;

@SpringBootTest
class JVMGCMetricsTest {
    @Autowired MeterRegistry registry;

    @Test
    void jvmGcPause_isRegistered() {
        // Spring Boot Actuator auto-registers jvm.gc.* metrics:
        Timer gcTimer = registry.find("jvm.gc.pause").timer();
        // Note: timer may be null before first GC, so use find().timers()
        Collection<Timer> gcTimers = registry.find("jvm.gc.pause").timers();
        // Some registries may not have this metric in test context
        // The important thing: the metric NAME is registered
        assertNotNull(registry, "MeterRegistry should be available");
        System.out.println("GC timers registered: " + gcTimers.size());
    }

    @Test
    void jvmMemoryUsed_isTracked() {
        // jvm.memory.used: heap + non-heap memory currently in use
        Gauge memGauge = registry.find("jvm.memory.used").gauge();
        // Memory gauge is always registered:
        assertNotNull(memGauge, "jvm.memory.used gauge should be registered");
        double usedMemory = memGauge.value();
        assertTrue(usedMemory > 0, "Memory usage should be positive");
        System.out.printf("Current heap used: %.1f MB%n", usedMemory / (1024 * 1024));
    }

    @Test
    void jvmGcCount_isPositive() {
        // jvm.gc.memory.promoted: bytes promoted to Old Gen
        // jvm.gc.live.data.size: estimated size of the Old Gen
        // These may be 0 early in test run — that's fine
        Collection<Gauge> gcGauges = registry.find("jvm.gc.live.data.size").gauges();
        System.out.println("GC live data size gauges: " + gcGauges.size());
        // Key assertion: MeterRegistry contains JVM metrics
        assertTrue(registry.getMeters().size() > 10,
            "Should have multiple JVM metrics registered");
    }
}

// SERVICE 1: payment-service (2GB container, high throughput, G1GC)
// MaxRAMPercentage=75 → heap = 2GB × 0.75 = 1.5GB
// Non-heap (25%): 512MB → Metaspace + threads + JIT
// G1GC flags:
// -XX:MaxRAMPercentage=75.0 -XX:+UseG1GC -XX:MaxGCPauseMillis=100
// -XX:G1HeapRegionSize=16m  (for 1.5GB heap)
// -XX:+HeapDumpOnOutOfMemoryError
// Expected: Minor GC every 2-5s (10ms), Major GC rarely (< 100ms)

// SERVICE 2: fraud-detector (4GB container, ML model in heap, ZGC)
// ML model (XGBoost/TensorFlow Lite) loaded into Java heap at startup
// Model size: ~1.5GB → needs large heap
// MaxRAMPercentage=75 → heap = 3GB
// Non-heap: 1GB (more JIT due to ML model inference paths)
// ZGC (sub-ms pauses critical for real-time fraud scoring):
// -XX:MaxRAMPercentage=75.0 -XX:+UseZGC
// -XX:SoftMaxHeapSize=2560m  (hint: try to stay under 2.5GB)
// -XX:+HeapDumpOnOutOfMemoryError -XX:HeapDumpPath=/tmp/
// ZGC: pauses < 1ms regardless of heap size!

// SERVICE 3: notification-worker (512MB container, batch)
// Batch processing: throughput > latency
// MaxRAMPercentage=70 (smaller → more overhead%)
// Heap = 512 × 0.70 = 358MB
// Non-heap: 154MB (tight for Spring Boot startup)
// Consider: 768MB container if Spring Boot startup takes > 30s (Metaspace pressure)
// G1GC (default, good for batch):
// -XX:MaxRAMPercentage=70.0 -XX:+UseG1GC
// -XX:MaxMetaspaceSize=128m  (cap Metaspace growth for batch)
// -XX:+HeapDumpOnOutOfMemoryError
// Expected: Major GC every batch cycle (acceptable for batch — throughput > latency)

public class MemorySizing {
    public static void main(String[] a) {
        System.out.printf("payment-service  2GB: heap=%.0fMB, GC=G1GC%n", 2048*0.75);
        System.out.printf("fraud-detector   4GB: heap=%.0fMB, GC=ZGC%n",  4096*0.75);
        System.out.printf("notification     512MB: heap=%.0fMB, GC=G1GC%n",512*0.70);
    }
}

import io.micrometer.core.instrument.*;
import org.springframework.scheduling.annotation.Scheduled;
import org.springframework.stereotype.Service;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import java.util.concurrent.atomic.AtomicLong;

@Service
public class AllocationRateMonitor {
    private static final Logger log = LoggerFactory.getLogger(AllocationRateMonitor.class);
    private final MeterRegistry registry;
    private long lastAllocatedBytes = 0;
    private long lastCheckMs = System.currentTimeMillis();

    AllocationRateMonitor(MeterRegistry registry) {
        this.registry = registry;
    }

    @Scheduled(fixedRate = 60_000)  // every 60 seconds
    public void logAllocationRate() {
        // jvm.gc.memory.allocated: total bytes allocated since JVM start
        Counter allocationCounter = registry.find("jvm.gc.memory.allocated").counter();
        if (allocationCounter == null) {
            log.debug("jvm.gc.memory.allocated not available yet");
            return;
        }

        long currentAllocated = (long) allocationCounter.count();
        long currentMs = System.currentTimeMillis();

        long deltaBytes = currentAllocated - lastAllocatedBytes;
        long deltaMs    = currentMs - lastCheckMs;
        double rateMBPerSec = (deltaBytes / 1_048_576.0) / (deltaMs / 1000.0);

        log.info("Object allocation rate: {:.1f} MB/s", rateMBPerSec);

        if (rateMBPerSec > 500) {
            log.warn("HIGH ALLOCATION RATE: {:.1f} MB/s — GC pressure risk!", rateMBPerSec);
            log.warn("Consider: object pooling, reduced object creation, or larger heap");
        }

        lastAllocatedBytes = currentAllocated;
        lastCheckMs = currentMs;
    }

    public static void main(String[] a) {
        System.out.println("Allocation rate: delta_allocated_bytes / elapsed_seconds");
    }
}

