import io.micrometer.core.instrument.*;
import org.springframework.scheduling.annotation.Scheduled;
import org.springframework.stereotype.*;
import java.lang.management.*;
import org.slf4j.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;

@Service
public class JVMObservabilityService {
    private static final Logger log = LoggerFactory.getLogger(JVMObservabilityService.class);
    private final MeterRegistry reg;
    private final Counter heapWarnings;

    JVMObservabilityService(MeterRegistry r) {
        reg = r;
        heapWarnings = Counter.builder("jvm.heap.warnings")
            .description("Times heap exceeded 80%")
            .register(reg);
        // Heap utilization gauge:
        Gauge.builder("jvm.heap.utilization", this, svc -> svc.getHeapUtilization())
            .description("Current heap utilization 0-1")
            .register(reg);
    }

    double getHeapUtilization() {
        MemoryMXBean mxBean = ManagementFactory.getMemoryMXBean();
        MemoryUsage heapUsage = mxBean.getHeapMemoryUsage();
        long max = heapUsage.getMax();
        return max > 0 ? (double) heapUsage.getUsed() / max : 0.0;
    }

    @Scheduled(fixedRate = 30_000)
    public void checkHeap() {
        double utilization = getHeapUtilization();
        log.info("JVM heap utilization: {:.1f}%", utilization * 100);
        if (utilization > 0.80) {
            heapWarnings.increment();
            log.warn("HEAP > 80%: {:.1f}% — consider increasing memory or investigating leak",
                utilization * 100);
        }
    }

    double getAlertThreshold() { return 0.80; }
}

@SpringBootTest
class JVMObsTest {
    @Autowired JVMObservabilityService svc;
    @Autowired MeterRegistry reg;
    @Test void heapGauge_registered() {
        assertNotNull(reg.find("jvm.heap.utilization").gauge());
        assertTrue(svc.getHeapUtilization() >= 0 && svc.getHeapUtilization() <= 1.0);
    }
    @Test void threshold_isCorrect() {
        assertEquals(0.80, svc.getAlertThreshold(), 0.001);
    }
}

