// GC TUNING EXPERIMENT DESIGN:
//
// STEP 1: Baseline measurement (default flags)
// Run load test: 1000 req/s, each creating 50 small objects (payment DTOs)
// Measure: GC pause via -Xlog:gc* logs and jvm.gc.pause metric
// Expected (default): Minor GC 10-20ms, Major GC 200-500ms every 45s
//
// STEP 2: Apply G1GC tuning
// -XX:MaxGCPauseMillis=100
// -XX:G1NewSizePercent=40      (more space for Young Gen → less promotion to Old)
// -XX:G1HeapRegionSize=16m     (larger regions for better heap utilization)
// -XX:ConcGCThreads=4          (more background GC threads)
// Expected: Minor GC 8-15ms, Major GC <100ms, less frequent
//
// STEP 3: For ultra-low latency
// -XX:+UseZGC (Java 17+)
// Expected: ALL pauses < 1ms!

@SpringBootTest
class GCTuningTest {
    @Autowired MeterRegistry registry;

    @Test void gcPauseTimer_accessible() {
        // Verify GC metrics infrastructure is working:
        Collection<Timer> gcTimers = registry.find("jvm.gc.pause").timers();
        // May be empty before any GC occurs (normal in fast test)
        System.out.println("GC timers available: " + gcTimers.size());
        // Key: MeterRegistry has JVM metrics registered
        assertTrue(registry.getMeters().stream()
            .anyMatch(m -> m.getId().getName().startsWith("jvm")),
            "Should have JVM metrics");
    }

    @Test void heapMemoryMetric_available() {
        Gauge heapUsed = registry.find("jvm.memory.used")
            .tag("area", "heap").gauge();
        assertNotNull(heapUsed, "jvm.memory.used{area=heap} should be registered");
        assertTrue(heapUsed.value() > 0);
    }
}

