import java.lang.management.*;
import java.util.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import io.micrometer.core.instrument.*;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import com.github.benmanes.caffeine.cache.Caffeine;
import java.util.concurrent.TimeUnit;

// LEAKY IMPLEMENTATION:
class LeakyCache {
    private static final Map<String, byte[]> CACHE = new HashMap<>();
    public void put(String key) {
        CACHE.put(key, new byte[10_240]);  // 10KB per entry, never evicted!
    }
    public int size() { return CACHE.size(); }
    public static void clearForTest() { CACHE.clear(); }
}

// FIXED IMPLEMENTATION:
class FixedCache {
    private final com.github.benmanes.caffeine.cache.Cache<String, byte[]> cache =
        Caffeine.newBuilder()
            .maximumSize(100)           // max 100 entries
            .expireAfterWrite(5, TimeUnit.MINUTES)  // evict after 5 min
            .build();
    public void put(String key) {
        cache.put(key, new byte[10_240]);
    }
    public long size() { return cache.estimatedSize(); }
}

@SpringBootTest
class MemoryLeakTest {
    MemoryMXBean memBean = ManagementFactory.getMemoryMXBean();

    @AfterEach void cleanup() { LeakyCache.clearForTest(); }

    @Test void leakyCache_growsUnbounded() {
        LeakyCache leaky = new LeakyCache();
        for (int i = 0; i < 100; i++) leaky.put("key-" + i);
        assertEquals(100, leaky.size(), "Leaky cache grew to 100 entries");
        // In production: this would be 1,000,000 entries → OOM
    }

    @Test void fixedCache_boundsSize() {
        FixedCache fixed = new FixedCache();
        for (int i = 0; i < 200; i++) fixed.put("key-" + i);
        // Caffeine evicts when > maximumSize:
        assertTrue(fixed.size() <= 110,  // some margin for Caffeine internals
            "Fixed cache should stay bounded");
    }

    @Test void heapUsage_within_bounds() {
        MemoryUsage heap = memBean.getHeapMemoryUsage();
        double utilization = (double) heap.getUsed() / heap.getMax();
        assertTrue(utilization < 0.90, "Heap should not be > 90% in test");
    }
}

