// JIT COMPILATION TIERS:
// Tier 1-3: C1 (client compiler) — fast compilation, less optimization
//   First 2000 invocations: interpreted, then C1 compiled
// Tier 4: C2 (server compiler) — slow compilation, heavy optimization
//   After ~10,000 invocations: C2 compiles (long-lived hot methods)
//
// RESULT: first 10,000 invocations of any method are slower
// Payment service: first 100 payments → slower than steady state

// JIT TRACKING VIA JMX:
class JITMonitor {
    public static long getCompilationTimeMs() {
        CompilationMXBean jit = ManagementFactory.getCompilationMXBean();
        return jit.isCompilationTimeMonitoringSupported() ?
            jit.getTotalCompilationTime() : -1;
    }

    public static int getLoadedClassCount() {
        return ManagementFactory.getClassLoadingMXBean().getLoadedClassCount();
    }
}

// WARM-UP STRATEGY:
// @EventListener(ApplicationStartedEvent.class)
// public void warmUp() {
//     log.info("JIT warm-up started...");
//     // Make 100 calls to key payment processing path:
//     for (int i = 0; i < 100; i++) {
//         paymentService.processTestPayment("WARMUP-" + i, 1.0);
//     }
//     log.info("JIT warm-up complete. JIT time: {}ms, Classes: {}",
//         JITMonitor.getCompilationTimeMs(),
//         JITMonitor.getLoadedClassCount());
// }

// K8S READINESS DELAY:
// readinessProbe.initialDelaySeconds: 60 (wait for JIT to warm up)
// Without warm-up: first requests after readiness are slow (p99 spike)
// With warm-up: JIT already compiled hot paths → stable p99 from first request

@SpringBootTest
class JITMetricsTest {
    @Test void jit_compilationTimeAccessible() {
        long jitTime = JITMonitor.getCompilationTimeMs();
        assertTrue(jitTime >= 0 || jitTime == -1, "JIT time should be >= 0 or -1");
        System.out.println("Total JIT compilation time: " + jitTime + "ms");
    }
    @Test void classLoading_trackable() {
        int classCount = JITMonitor.getLoadedClassCount();
        assertTrue(classCount > 100, "Spring Boot loads many classes");
        System.out.println("Loaded classes: " + classCount);
    }
}

import io.micrometer.core.instrument.*;
import java.lang.management.*;
import org.springframework.stereotype.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import com.github.benmanes.caffeine.cache.Caffeine;
import java.util.concurrent.TimeUnit;

@Service
class RazorpayJVMObservability {
    private final MeterRegistry reg;
    private final com.github.benmanes.caffeine.cache.Cache<String,byte[]> safeCache;

    RazorpayJVMObservability(MeterRegistry r) {
        reg = r;
        safeCache = Caffeine.newBuilder().maximumSize(500).expireAfterWrite(10,TimeUnit.MINUTES).build();
        Gauge.builder("rp.jvm.heap.utilization", this, s -> s.heapUtilization()).register(reg);
        Gauge.builder("rp.cache.size", safeCache, c -> c.estimatedSize()).register(reg);
    }

    double heapUtilization() {
        MemoryUsage h = ManagementFactory.getMemoryMXBean().getHeapMemoryUsage();
        return h.getMax() > 0 ? (double) h.getUsed() / h.getMax() : 0.0;
    }

    long jitTime() {
        CompilationMXBean c = ManagementFactory.getCompilationMXBean();
        return c.isCompilationTimeMonitoringSupported() ? c.getTotalCompilationTime() : 0;
    }

    void cacheData(String key) { safeCache.put(key, new byte[1024]); }
    long cacheSize() { return safeCache.estimatedSize(); }
}

@SpringBootTest
class M22T1SynthesisTest {
    @Autowired RazorpayJVMObservability svc;
    @Autowired MeterRegistry reg;

    @Test void heapGauge_registeredAndValid(){
        Gauge g = reg.find("rp.jvm.heap.utilization").gauge();
        assertNotNull(g);
        double u = g.value();
        assertTrue(u >= 0.0 && u <= 1.0, "Utilization should be 0-1, was: " + u);
    }
    @Test void safeCache_bounded(){
        for (int i=0;i<1000;i++) svc.cacheData("k-"+i);
        assertTrue(svc.cacheSize() <= 600, "Cache should be bounded by maximumSize=500");
    }
    @Test void jitTime_accessible(){
        assertTrue(svc.jitTime() >= 0, "JIT compilation time should be >= 0");
    }
}
